// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
  const navigate = useNavigate();

  const initialFormState = {
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
    loaiHinhCheBienGo: '', nguonGocGo: '',
    loaiCoSoDangKy: '',
    tenLamSan: [],            // <-- đổi sang mảng
    tenKhoaHoc: [],           // <-- đổi sang mảng
    issueDate: '', expiryDate: '',
    trangThai: 'Đang hoạt động',
    ghiChu: ''
  };

  const [formData, setFormData] = useState(initialFormState);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        const decodedToken = jwtDecode(token);
        if (decodedToken.role === 'admin') {
          setIsAdmin(true);
        }
      } catch (err) {
        localStorage.removeItem('token');
        navigate('/login');
      }
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  }, []);

  const resetForm = useCallback(() => {
    setFormData(initialFormState);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' });
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' });

    const token = localStorage.getItem('token');
    if (!token) {
      setMessage({ type: 'error', text: 'Bạn chưa đăng nhập.' });
      setLoading(false);
      navigate('/login');
      return;
    }

    try {
      const response = await axios.post('http://localhost:10000/api/farms', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSuccessMessage('Đăng ký cơ sở thành công!');
      setMessage({ type: 'success', text: 'Đăng ký cơ sở thành công!' });
      resetForm();
    } catch (err) {
      setError('Đăng ký cơ sở thất bại.');
      setMessage({ type: 'error', text: 'Đăng ký cơ sở thất bại.' });
    } finally {
      setLoading(false);
    }
  };

  const handleMultiSpeciesChange = (e) => {
    const selected = Array.from(e.target.selectedOptions).map(opt => opt.value);
    setFormData(prev => ({
      ...prev,
      tenLamSan: selected,
      tenKhoaHoc: selected.map(name => {
        const s = speciesOptions.find(sp => sp.name === name);
        return s?.scientificName || '';
      })
    }));
  };

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở</h2>

      {message.type && (
        <div className={`message ${message.type}`}>
          {message.text}
          <button onClick={() => setMessage({ type: '', text: '' })}>x</button>
        </div>
      )}

      <form onSubmit={handleSubmit} className="khai-bao-form">
        {/* Thông tin cơ sở */}
        <section className="khai-bao-section">
          <h3>Thông tin cơ sở</h3>
          {/* ... các trường khác giữ nguyên ... */}
        </section>

        {/* Người đại diện */}
        <section className="khai-bao-section">
          <h3>Thông tin người đại diện</h3>
          {/* ... giữ nguyên ... */}
        </section>

        <section className="khai-bao-section">
          <h3>Loại cơ sở đăng ký</h3>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Chọn loại:</label>
            <select
              id="loaiCoSoDangKy"
              name="loaiCoSoDangKy"
              value={formData.loaiCoSoDangKy}
              onChange={handleChange}
              required
            >
              <option value="">-- Chọn --</option>
              <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở gỗ</option>
            </select>
          </div>
        </section>

        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Cơ sở gây nuôi</h3>
            {/* Các trường khác giữ nguyên */}
            <div className="form-group">
              <label htmlFor="tenLamSan">Loài nuôi:</label>
              <select
                id="tenLamSan"
                name="tenLamSan"
                multiple
                value={formData.tenLamSan}
                onChange={handleMultiSpeciesChange}
              >
                {speciesOptions.map((species, idx) => (
                  <option key={idx} value={species.name}>{species.name}</option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
              <textarea
                id="tenKhoaHoc"
                name="tenKhoaHoc"
                value={formData.tenKhoaHoc.join('\n')}
                readOnly
                disabled
                rows={formData.tenKhoaHoc.length || 1}
              />
            </div>
          </section>
        )}

        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
          <section className="khai-bao-section">
            <h3>Cơ sở chế biến gỗ</h3>
            {/* ... giữ nguyên ... */}
            <div className="form-group">
              <label htmlFor="tenLamSan">Tên lâm sản:</label>
              <input type="text" name="tenLamSan" value={formData.tenLamSan.join(', ')} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
              <input type="text" name="tenKhoaHoc" value={formData.tenKhoaHoc.join(', ')} onChange={handleChange} />
            </div>
          </section>
        )}

        {/* Thông tin giấy phép */}
        <section className="khai-bao-section">
          <h3>Giấy phép</h3>
          {/* ... giữ nguyên ... */}
        </section>

        <div className="form-actions">
          <button type="submit" disabled={loading}>
            {loading ? 'Đang gửi...' : 'Đăng ký cơ sở'}
          </button>
          <button type="button" onClick={resetForm} disabled={loading}>
            Đặt lại
          </button>
        </div>
      </form>
    </div>
  );
}

export default KhaiBaoCoSo;
